const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const quoteStep = (step: QuoteStep): { premium: number } => {
  const itemTotal = step.items.reduce((sum, item) => {
    const base = BASE_PREMIUM[item.type];
    return sum + base * (1 + FIRST_INSURANCE_SURCHARGE);
  }, 0);
  return { premium: Math.ceil(itemTotal + PROCESSING_FEE) };
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

