const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const itemBasePremiums = (items: Item[]): number[] => {
  const components: Item[] = [];
  const mainItems: Item[] = [];
  for (const item of items) {
    (COMPONENT_TYPES.has(item.type) ? components : mainItems).push(item);
  }
  const basePremiums = mainItems.map((item) => BASE_PREMIUM[item.type]);
  const countsByType = new Map<string, number>();
  for (const c of components) {
    countsByType.set(c.type, (countsByType.get(c.type) ?? 0) + 1);
  }
  for (const [, count] of countsByType) {
    if (count === COMPONENT_BLOCK_SIZE) {
      basePremiums.push(COMPONENT_BLOCK_PREMIUM);
    } else {
      basePremiums.push(count * BASE_PREMIUM.rune);
    }
  }
  return basePremiums;
};

