type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

// MHPCO rounds premiums up in its own favor. A float-precision guard avoids
// surprises like 197.5 + 0 rendering as 197.5000000001 and rounding to 198
// when the true mathematical value was already on an integer boundary.
const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(Math.round(amount * 1e6) / 1e6);

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const componentGroupPremium = (type: string, count: number): number =>
  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * BASE_PREMIUM[type];

const itemBasePremiums = (items: Item[]): number[] => {
  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
  const componentCountsByType = new Map<string, number>();
  for (const c of components) {
    componentCountsByType.set(c.type, (componentCountsByType.get(c.type) ?? 0) + 1);
  }
  const mainPremiums = mainItems.map((item) => BASE_PREMIUM[item.type]);
  const componentPremiums = [...componentCountsByType].map(([type, count]) =>
    componentGroupPremium(type, count),
  );
  return [...mainPremiums, ...componentPremiums];
};

const quoteStep = (step: QuoteStep): { premium: number } => {
  const itemTotal = itemBasePremiums(step.items).reduce(
    (sum, base) => sum + base * (1 + FIRST_INSURANCE_SURCHARGE),
    0,
  );
  const total = itemTotal + PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(total) };
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

