import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ─────────────────────────────────────────────────────────────────
  // Edge cases — simplest first
  // ─────────────────────────────────────────────────────────────────
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // ─────────────────────────────────────────────────────────────────
  // Single-item base premiums (no modifiers, customer 0 yrs, first quote)
  // First insurance surcharge (+10%) applies to every item; processing fee +5
  // ─────────────────────────────────────────────────────────────────
  it("single sword (no modifiers, new customer) → 100 base + 10 first ins + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (no modifiers, new customer) → 60 + 6 + 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (no modifiers, new customer) → 80 + 8 + 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (no modifiers, new customer) → 40 + 4 + 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ─────────────────────────────────────────────────────────────────
  // Components — block-of-3 rule
  // ─────────────────────────────────────────────────────────────────
  it("2 runes → 50 G base premium → 60 G total (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block applies) → 71 G total", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base premium (no block — block requires exactly 3) → 115 G total", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base premium (no block grouping; 7×25) → 198 G total", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: Array(7).fill({ type: "rune" }) },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // ─────────────────────────────────────────────────────────────────
  // "Alike" components — same type only, not same family
  // ─────────────────────────────────────────────────────────────────
  it("2 runes + 1 moonstone → 75 G base premium (no block: different types) → 88 G total", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks) → 137 G total", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ─────────────────────────────────────────────────────────────────
  // Item-specific modifiers (in isolation)
  // ─────────────────────────────────────────────────────────────────
  it("cursed sword (new customer) → 100 base + 50 curse + 10 first ins + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("sword with enchantment exactly 5 → high-enchantment +30% applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");

  // ─────────────────────────────────────────────────────────────────
  // Policy-wide modifiers (in isolation)
  // ─────────────────────────────────────────────────────────────────
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("customer with 1 year → no loyalty discount");
  it.todo("first insurance surcharge (+10%) applies to each item in a quote");
  it.todo("follow-up contract discount (−15%) applies to second and later quotes");

  // ─────────────────────────────────────────────────────────────────
  // Modifier scope on multi-item policies (from ❓)
  // ─────────────────────────────────────────────────────────────────
  it.todo("cursed sword + plain amulet → base 160, +50G curse (only on sword) = 210 G before fee");

  // ─────────────────────────────────────────────────────────────────
  // Rounding in MHPCO's favor
  // ─────────────────────────────────────────────────────────────────
  it.todo("premium 197.5 G → 198 G (rounded up)");

  // ─────────────────────────────────────────────────────────────────
  // Integration examples
  // ─────────────────────────────────────────────────────────────────
  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
  it.todo("long-standing (3yr) customer's second contract, cursed sword enchantment 7 → 160 G");

  // ─────────────────────────────────────────────────────────────────
  // Quote errors
  // ─────────────────────────────────────────────────────────────────
  it.todo("quote with unknown item type (e.g. broomstick) → throws error");

  // ─────────────────────────────────────────────────────────────────
  // Claims — standard reimbursement
  // ─────────────────────────────────────────────────────────────────
  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 - 100 deductible)");
  it.todo("damage to a rune (insurance 250), damage 200 → payout 100 (200 - 100 deductible)");

  // ─────────────────────────────────────────────────────────────────
  // Claims — special clauses
  // ─────────────────────────────────────────────────────────────────
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (50% then deductible)");

  // ─────────────────────────────────────────────────────────────────
  // Claims — deductible per damage event
  // ─────────────────────────────────────────────────────────────────
  it.todo("dragon attack damages insured sword (500) and amulet (300) → payout 600 (deductible per item)");

  // ─────────────────────────────────────────────────────────────────
  // Claims — multiple items of same type
  // ─────────────────────────────────────────────────────────────────
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("two sword damages on two-sword policy → each damage has its own deductible");
  it.todo("damages array contains more entries of a type than insured → error (non-zero exit)");

  // ─────────────────────────────────────────────────────────────────
  // Claims — cap exhaustion
  // ─────────────────────────────────────────────────────────────────
  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword (insurance value 1000) → cap 2000 (premium modifiers don't raise cap)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
  it.todo("sword policy (cap 2000); 1st claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword policy (cap 2000) after 1st claim; 2nd claim 1500 → payout 600, remainingCap 0");

  // ─────────────────────────────────────────────────────────────────
  // Payout rounding
  // ─────────────────────────────────────────────────────────────────
  it.todo("payout 350.5 G → 350 G (rounded down)");

  // ─────────────────────────────────────────────────────────────────
  // Claim errors
  // ─────────────────────────────────────────────────────────────────
  it.todo("claim references damage entry whose item is not part of policy → error");
  it.todo("claim damages an item of unknown type → error");
  it.todo("claim contains damage entry with amount -200 → error");
});

