  const total = itemSurchargeTotal + policyBase * policyWideRate(customer, quoteIndex) + PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(total) };
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  let quoteIndex = 0;
  const results = scenario.steps.map((step) => {
    const result = quoteStep(step, scenario.customer, quoteIndex);
    quoteIndex += 1;
    return result;
  });
  return { results };
