  for (const c of components) {
    componentCountsByType.set(c.type, (componentCountsByType.get(c.type) ?? 0) + 1);
  }
  const mainLines = mainItems.map(mainItemLine);
  const componentLines = [...componentCountsByType].map(([type, count]) => ({
    base: componentGroupPremium(type, count),
    itemSurchargeRate: 0,
  }));
  return [...mainLines, ...componentLines];
};

const linePremium = (line: PremiumLine): number =>
  line.base * (1 + FIRST_INSURANCE_SURCHARGE + line.itemSurchargeRate);

const policyWideRate = (customer: Scenario["customer"], quoteIndex: number): number => {
  let rate = 0;
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
  if (quoteIndex > 0) rate -= FOLLOW_UP_DISCOUNT;
  return rate;
};

const quoteStep = (
  step: QuoteStep,
  customer: Scenario["customer"],
  quoteIndex: number,
): { premium: number } => {
  const lines = itemPremiumLines(step.items);
  const itemSurchargeTotal = lines.map(linePremium).reduce((sum, p) => sum + p, 0);
  const policyBase = lines.reduce((sum, l) => sum + l.base, 0);
  const total = itemSurchargeTotal + policyBase * policyWideRate(customer, quoteIndex) + PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(total) };
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  let quoteIndex = 0;
  const results = scenario.steps.map((step) => {
    const result = quoteStep(step, scenario.customer, quoteIndex);
    quoteIndex += 1;
    return result;
  });
  return { results };
};

