const countByType = <T extends { type?: string; itemType?: string }>(items: T[], key: "type" | "itemType"): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    const t = item[key]!;
    counts.set(t, (counts.get(t) ?? 0) + 1);
  }
  return counts;
};

const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
  const policy = policies[step.policy];
  const policyCounts = countByType(policy.items, "type");
  const damageCounts = countByType(step.incident.damages, "itemType");
  for (const [type, count] of damageCounts) {
    if (count > (policyCounts.get(type) ?? 0)) {
      throw new Error(`Claim has more ${type} damages than insured`);
    }
  }
  const totalDamage = step.incident.damages.reduce((sum, d) => {
    const item = policy.items.find((i) => i.type === d.itemType)!;
    return sum + damagePayout(d, item);
  }, 0);
  const payout = roundDownInMHPCOFavor(totalDamage);
  policy.cap -= payout;
  return { payout, remainingCap: policy.cap };
};

